var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……누구인가.","JPN":"……何者だ。","ENG":"...Who is it?","TWN":"……是誰？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"누가 악단이 만들어낸 흉측한 선박을 다시금 건드리는가.","JPN":"楽団が作り出した忌まわしい船舶に触れたのは、どこの者だ。","ENG":"Who dares touch the vile ship made by the Orchestra?","TWN":"是誰再次觸碰了樂團製造的醜陋艦船？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그 선박은 좌초되었으나, 여전히 역병의 악취가 가득한 상자와 같을지니.","JPN":"その船舶は座礁したが、今以て疫病の悪臭に満ちた箱。","ENG":"The ship has been stranded. Yet, it reeks like a chest full of the stench of the plague.","TWN":"那艘船雖然擱淺了，但仍像一個充滿瘟疫惡臭的箱子。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"함부로 상자를 열어 버린 자 또한 필히 악한 의도를 가지고 있을 터.","JPN":"迂闊に箱を開けたというのなら、さぞ悪意を持っているのであろう。","ENG":"Anyone careless enough to open that chest is bound to have evil intentions.","TWN":"擅自打開之人必定也懷有惡意。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇군요. 아무래도 당신은 절 기억하지 못하는 모양이네요.","JPN":"そうですか。どうやらあなたは私のことを覚えていないようですね。","ENG":"I see. It seems that you don't remember me.","TWN":"原來如此。看來你並不記得我了。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후훗…….","JPN":"ふふっ……","ENG":"Haha...","TWN":"呵呵……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그럴 거라고 짐작은 하고 있었지만, 막상 예상이 맞아 떨어지니 참 섭섭하군요.","JPN":"予想はしていました。でも、いざ予想が当たると寂しいものですね。","ENG":"I was anticipating this, but I'm disappointed that my prediction turned out to be right.","TWN":"雖然我猜到了會這樣，但真的應驗了還是有點失落。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"왜냐하면 그날 이후, 저는 단 한 순간도 당신을 잊은 적이 없으니까.","JPN":"なぜならあの日以来、私は一瞬たりともあなたを忘れたことがないのだから。","ENG":"Because since that day, I have never forgotten about you.","TWN":"從那天起，我可是從未忘記過你。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"너는……?","JPN":"そなたは……？","ENG":"You are...?","TWN":"你是……？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래요.","JPN":"そうです。","ENG":"Very well.","TWN":"沒錯。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그때는 알지 못했지만, 이제는 알고 있답니다.","JPN":"あの時はわかりませんでしたが、今はわかります。","ENG":"I didn't know then, but I know now.","TWN":"那時候不知道，但現在我知道了。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이미 그림자로 몰락해 버린 당신을 움직이게 만드는 망집이 후회라는 것.","JPN":"すでにシャドウになり下がったあなたを動かす妄執は後悔だということ。","ENG":"That the obsession that drives you, an already fallen Shadow, is regret.","TWN":"已經墮入陰影的你，被一種名為後悔的妄念所驅動。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"기계적으로 후회를 반복할 뿐, 당신은 아무런 대책 없이 수많은 세계를 방랑해 왔다는 것.","JPN":"機械的に後悔を繰り返すだけで、あなたはなんの策もなしに数多の世界を放浪してきたのだということ。","ENG":"You repeat your regrets while wandering countless worlds without any solution.","TWN":"機械地重複著這種感情，你在無數個世界中漫無目的地遊蕩。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신에게 있어, 저의 세계는 그저 마왕을 막아내지 못한 무수한 실패들 중 하나였다는 것.","JPN":"あなたにとって私の世界は、魔王を止められなかった、無数の失敗の一つにすぎなかったということ。","ENG":"To you, my world is one of many failures that couldn't stop the Demon Lord.","TWN":"對你來說，我的世界只不過是無數未能阻止魔王的失敗了的其中之一。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고…….","JPN":"そして……","ENG":"And...","TWN":"以及……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 마왕 타기리온을 만들어낸 장본인이라는 것.","JPN":"あなたが、魔王タギリオンを生み出した張本人だということ。","ENG":"That you are you one who created the Demon Lord Thagirion.","TWN":"你就是創造出魔王塔基里昂的罪魁禍首。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"나의 우행을 부정할 생각은 없을지니.","JPN":"我の愚行を否定するつもりはない。","ENG":"I will not deny my foolish deeds.","TWN":"我並不打算否認我的愚行。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그 끝에 다다른 것이 결국 부질없는 후회뿐일지라도.","JPN":"辿り着いたその先が、空虚な後悔だけであろうとも。","ENG":"Even if what awaits me at the end is nothing but regret.","TWN":"即使到頭來獲得的只是徒勞的後悔。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"나는 속죄를 위해 싸우겠다.","JPN":"我は贖罪のために戦い続けよう。","ENG":"I will fight for atonement.","TWN":"我會為了贖罪而戰。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……보세요.","JPN":"……ほら。","ENG":"...Look.","TWN":"……看啊。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신은 또 그런 태도를 보이죠.","JPN":"あなたはまたそんな態度を見せる。","ENG":"You're showing that attitude again.","TWN":"你又擺出那種態度了。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제가 뭘 숨기고 있는지 모르면서, 무슨 목적을 감추고 있는지도 모르면서…….","JPN":"私が何を隠しているのかも知らず、何の目的で動いているのかも知らずに……","ENG":"You don't know what I'm hiding, or my purpose...","TWN":"你不知道我在隱藏什麼，也不知道我有什麼目的……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그저 홀로, 오로지 고독하게…….","JPN":"ただ一人、孤独に……","ENG":"You are alone... Isolated...","TWN":"只是獨自一人，孤獨地……"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"누구에게도 이해받지 못하고, 누구의 도움도 바라지 않으며.","JPN":"誰にも理解されず、誰の助けも求めず……","ENG":"No one to understand you, and not wanting help from others.","TWN":"不渴求理解，也不乞求幫助。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"결과적으로는……. 혼자서는 감당조차 할 수 없는 문제를 끌어안은 주제에……!!","JPN":"その結果……一人では耐えきれない問題を抱えているくせに……！！","ENG":"As a result... you have taken upon yourself a problem that you can't handle on your own...!!","TWN":"結果卻是……抱著自己無法承受的問題……！！"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};